const cfg = $('Set · Config').first().json;
const r = $input.first().json;
const clients = r.list || [];
if (!clients.length) return [];
return clients.map(c => ({ json: { ...cfg, client: c } }));

const item = $input.first().json;
const c = item.client;
const workflowId = c.n8n_workflow_id || '';
const lastSeen = c.last_seen ? new Date(c.last_seen) : null;
const hoursSinceActive = lastSeen ? (Date.now() - lastSeen.getTime()) / 3600000 : 999;
return [{ json: {
  ...item,
  clientId: String(c.Id),
  clientName: c.client_name || 'Unknown',
  workflowId,
  lastSeen: c.last_seen || null,
  hoursSinceActive: Math.round(hoursSinceActive * 10) / 10,
  hasWorkflowId: !!workflowId
} }];

const ctx = $('Code · Prep check').first().json;
const wfResult = $('HTTP · Check workflow').first().json;
const errResult = $('HTTP · Check error rate').first().json;
const totalResult = $('HTTP · Check total msgs').first().json;

const issues = [];

// 1. Workflow active check
if (ctx.hasWorkflowId) {
  const wfActive = wfResult.active === true || wfResult.data?.active === true;
  if (!wfActive && !wfResult.error) issues.push('workflow_inactive');
  if (wfResult.error || wfResult.statusCode >= 400) issues.push('workflow_not_found');
} 

// 2. Inactivity check (no messages in N hours despite being active)
if (ctx.hoursSinceActive > ctx.inactive_hours) {
  issues.push('no_recent_activity');
}

// 3. Error rate check
const errorCount = (errResult.list || []).length;
const totalCount = (totalResult.list || []).length;
const errorRate = totalCount > 0 ? Math.round(errorCount / totalCount * 100) : 0;
if (errorRate > ctx.error_rate_threshold && totalCount >= 5) {
  issues.push('high_error_rate');
}

if (!issues.length) return []; // healthy — skip alert

const alertBody = {
  client_id: ctx.clientId,
  client_name: ctx.clientName,
  issues,
  error_rate_pct: errorRate,
  error_count_1h: errorCount,
  total_msgs_1h: totalCount,
  hours_since_active: ctx.hoursSinceActive,
  workflow_id: ctx.workflowId,
  checked_at: new Date().toISOString()
};

return [{ json: { ...ctx, _alertBody: alertBody, _issues: issues } }];
